1	const NEIGHBOR_OFFSETS: [number, number][] = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [ 0, -1],          [ 0, 1],
4	  [ 1, -1], [ 1, 0], [ 1, 1],
5	];
6	
7	export function nextGeneration(grid: boolean[][]): boolean[][] {
8	  if (grid.length === 0) return [];
9	
10	  const rows = grid.length;
11	  const cols = grid[0].length;
12	
13	  const isInBounds = (r: number, c: number): boolean =>
14	    r >= 0 && r < rows && c >= 0 && c < cols;
15	
16	  const countNeighbors = (r: number, c: number): number =>
17	    NEIGHBOR_OFFSETS.filter(([dr, dc]) => isInBounds(r + dr, c + dc) && grid[r + dr][c + dc]).length;
18	
19	  const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
20	  const isReborn = (neighbors: number): boolean => neighbors === 3;
21	
22	  const nextGrid = grid.map((row, r) =>
23	    row.map((cell, c) => {
24	      const neighbors = countNeighbors(r, c);
25	      return cell ? survives(neighbors) : isReborn(neighbors);
26	    })
27	  );
28	
29	  const hasLiveCell = nextGrid.some(row => row.some(cell => cell));
30	  return hasLiveCell ? nextGrid : [];
31	}
